    int i;

    fprintf(fh, "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n");
    fprintf(fh, "<psml version=\"" PSML_VERSION "\" creator=\"%s/%s\">\n", PACKAGE, VERSION);
